<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1">
<title>Route Room</title>
<style>
@import url('https://fonts.googleapis.com/css2?family=DM+Mono:wght@400;500&family=Fraunces:opsz,wght@9..144,600;9..144,800&display=swap');
:root{--ink:#17202b;--paper:#f4ecd9;--orange:#ed613d;--blue:#177a91;--gold:#e5b93e;--line:#263844}*{box-sizing:border-box}body{margin:0;min-height:100vh;color:var(--ink);font-family:'DM Mono',monospace;background:radial-gradient(circle at 15% 12%,#fff9e8 0 8%,transparent 30%),repeating-linear-gradient(-35deg,#f4ecd9 0 2px,#efe4cc 2px 4px);padding:clamp(16px,4vw,56px)}main{max-width:1050px;margin:auto}.mast{display:flex;align-items:flex-end;justify-content:space-between;gap:22px;border-bottom:5px solid var(--ink);padding-bottom:20px}.eyebrow{letter-spacing:.16em;font-size:11px;color:var(--orange);font-weight:bold}.mast h1{font:800 clamp(48px,10vw,105px)/.78 Fraunces,serif;letter-spacing:-.08em;margin:9px 0 0}.stamp{border:2px solid var(--orange);color:var(--orange);padding:11px 9px;transform:rotate(4deg);font-size:10px;text-align:center;line-height:1.3}.intro{max-width:680px;line-height:1.65;font-size:14px;margin:23px 0 28px}.grid{display:grid;grid-template-columns:1.35fr .8fr;gap:22px}.board{position:relative;min-height:500px;overflow:hidden;border:4px solid var(--ink);background:#91ccd2;background-image:radial-gradient(#d7eff0 1px,transparent 1px);background-size:12px 12px;box-shadow:8px 8px 0 var(--ink)}.land{position:absolute;border-radius:48% 42% 55% 35%;background:#dfc76c;opacity:.78}.land.one{width:65%;height:48%;left:-12%;top:-12%;transform:rotate(14deg)}.land.two{width:62%;height:47%;right:-20%;bottom:-17%;transform:rotate(-13deg)}.city{position:absolute;z-index:3;border:0;border-radius:50%;width:18px;height:18px;background:var(--ink);box-shadow:0 0 0 3px #f6edcf;cursor:pointer;transition:transform .15s}.city:hover,.city.sel{transform:scale(1.35);background:var(--orange)}.city span{position:absolute;top:23px;left:50%;transform:translateX(-50%);font-size:10px;white-space:nowrap;font-weight:bold}.route{position:absolute;height:8px;border-radius:12px;background:repeating-linear-gradient(90deg,var(--line) 0 13px,transparent 13px 19px);transform-origin:0 50%;z-index:2;opacity:.8}.route.taken{background:repeating-linear-gradient(90deg,var(--orange) 0 13px,transparent 13px 19px);opacity:1}.side{border:4px solid var(--ink);background:#fff7e5;padding:20px;box-shadow:7px 7px 0 var(--ink)}.side h2{font:800 27px/1 Fraunces,serif;margin:0 0 9px}.ticket{border:2px dashed var(--ink);padding:16px;margin:17px 0;background:linear-gradient(120deg,#fff6db,#f5df9d)}.ticket small{display:block;color:var(--blue);letter-spacing:.12em;font-weight:bold;margin-bottom:8px}.route-name{font:800 24px/1.08 Fraunces,serif}.points{font-size:12px;margin-top:11px}.score{display:flex;gap:8px;align-items:center;margin:20px 0;font-size:13px}.score b{font:800 28px Fraunces,serif;color:var(--orange)}button{font:500 13px 'DM Mono',monospace;background:var(--orange);color:#fff;border:3px solid var(--ink);padding:13px 15px;box-shadow:4px 4px 0 var(--ink);cursor:pointer}button:active{transform:translate(3px,3px);box-shadow:1px 1px 0 var(--ink)}.msg{min-height:48px;font-size:12px;line-height:1.55;margin:17px 0 0}.legend{display:flex;gap:13px;flex-wrap:wrap;font-size:10px;margin-top:15px}.dot{display:inline-block;width:10px;height:10px;border-radius:50%;background:var(--ink);margin-right:5px}.dot.orange{background:var(--orange)}footer{font-size:11px;margin-top:24px}a{color:var(--ink);text-decoration-color:var(--orange);text-decoration-thickness:2px}@media(max-width:720px){.grid{grid-template-columns:1fr}.board{min-height:420px}.mast{align-items:flex-start}.stamp{display:none}}
</style>
</head><body><main>
<header class="mast"><div><div class="eyebrow">THE POCKET RAILWAY DEPARTMENT</div><h1>ROUTE<br>ROOM</h1></div><div class="stamp">ADMIT ONE<br>TO WONDER</div></header>
<p class="intro">A tiny, no-rules-lawyering railway puzzle. Claim links between cities to complete the ticket before the map turns into a very polite transportation catastrophe.</p>
<section class="grid"><div class="board" id="board"><i class="land one"></i><i class="land two"></i></div><aside class="side"><h2>Your ticket</h2><p style="font-size:11px;line-height:1.6">Tap a city, then an adjacent city. Every claimed rail costs one little wooden train (imaginary, mercifully).</p><div class="ticket"><small>DESTINATION TICKET</small><div class="route-name" id="goal">Maple Bay → Starfall</div><div class="points">Worth <b id="worth">12</b> points · take the scenic route if you dare</div></div><div class="score">CLAIMED <b id="score">0</b> / <span id="needed">4</span></div><button id="new">STAMP A NEW TICKET</button><div class="msg" id="msg">Choose a station to begin. Black dots are stations; orange tracks are yours.</div><div class="legend"><span><i class="dot"></i>station</span><span><i class="dot orange"></i>your track</span></div></aside></section>
<footer>Inspired by Jon's <a href="https://jona.ca/2004/03/ra-ticket-to-ride.html">post about Ra and Ticket To Ride</a>.</footer>
</main><script>
const cities=[['Maple Bay',15,28],['Copperfield',39,18],['Pinewatch',70,24],['Starfall',84,48],['Harbour',56,54],['Juniper',26,67],['Wren',72,78],['Moss',43,86]];
const links=[[0,1],[1,2],[2,3],[0,5],[5,4],[4,3],[5,7],[7,6],[6,3],[1,4],[4,6],[4,7]];
const tickets=[[0,3,12,[0,1,2,3]],[5,2,11,[5,4,1,2]],[0,6,14,[0,5,7,6]],[1,7,10,[1,4,7]],[5,3,13,[5,4,3]]];
const board=document.querySelector('#board'),msg=document.querySelector('#msg');let picked=null,claimed=[],ticket=tickets[0];
function pos(i){return cities[i].slice(1)}function draw(){board.querySelectorAll('.city,.route').forEach(x=>x.remove());links.forEach((l,i)=>{let[a,b]=l,[x,y]=pos(a),[x2,y2]=pos(b),dx=x2-x,dy=y2-y,len=Math.hypot(dx,dy);let r=document.createElement('i');r.className='route '+(claimed.includes(i)?'taken':'');r.style.cssText=`left:${x}%;top:${y}%;width:${len}%;transform:rotate(${Math.atan2(dy,dx)*180/Math.PI}deg)`;board.append(r)});cities.forEach((c,i)=>{let e=document.createElement('button');e.className='city '+(picked===i?'sel':'');e.style.left=`calc(${c[1]}% - 9px)`;e.style.top=`calc(${c[2]}% - 9px)`;e.innerHTML='<span>'+c[0]+'</span>';e.onclick=()=>choose(i);board.append(e)})}
function choose(i){if(picked===null){picked=i;msg.textContent='From '+cities[i][0]+': now choose a neighbouring station.';draw();return}let ix=links.findIndex((l,n)=>!claimed.includes(n)&&l.includes(picked)&&l.includes(i));if(ix<0){msg.textContent='No unclaimed direct line there. Pick a neighbouring station.';picked=null;draw();return}claimed.push(ix);picked=i;document.querySelector('#score').textContent=claimed.length;msg.textContent='Track claimed: '+cities[links[ix][0]][0]+' — '+cities[links[ix][1]][0]+'.';draw();check()}
function check(){let seen=new Set([ticket[0]]),changed=true;while(changed){changed=false;claimed.forEach(i=>{let[a,b]=links[i];if(seen.has(a)&&!seen.has(b)){seen.add(b);changed=true}if(seen.has(b)&&!seen.has(a)){seen.add(a);changed=true}})}if(seen.has(ticket[1])){msg.innerHTML='★ Ticket complete! <b>'+ticket[2]+' points</b> and a first-class view of the tiny painted mountains.';}}
function fresh(){ticket=tickets[Math.floor(Math.random()*tickets.length)];claimed=[];picked=null;document.querySelector('#goal').textContent=cities[ticket[0]][0]+' → '+cities[ticket[1]][0];document.querySelector('#worth').textContent=ticket[2];document.querySelector('#needed').textContent='?';document.querySelector('#score').textContent='0';msg.textContent='Fresh ink, fresh possibility. Choose a station to begin.';draw()}
document.querySelector('#new').onclick=fresh;draw();
</script></body></html>
